head.script:
/**
 * 화 면 명 : 터미널본선스케줄등록
 * 메뉴경로 : 물류/공통(통합)/본선/선박/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ds/op/rscconfirm/transrscconfirm/tb_030_01_01b.jsp
 * 작 성 자 : 박원
 * 작 업 일 : 2026-03-09
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-03-09      박원      최초작성
 *    - 2026-04-03      이진우    본선관리번호검색(tb_030_01_02p) 팝업 연결
 *    - 2026-04-21      이진우    T-5489 결함조치
 *    - 2026-04-22      이진우    T-7336 결함조치
 */

/*
ed_berthCd 차후 style display:none 처리 해야함.

scwin.f_openPopUp 호출팝업 개발공수에 안잡혀있어 유사화면으로
tb_030_01_02p -> op_204_01_07p

공통코드팝업 UDC 제외 전체 안되어있음

수정은 테스트했는데 저장,삭제에 대한 시나리오 필요. 저장시 걸리는 로직이 너무 많음
*/

//전역변수-save인지 update인지 구분해서 cmd호출 0=save, 1=update
scwin.validSaveOrUpdate = 0;
scwin.cvsslMgntNo = "";

scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)


scwin.onpageload = function() {
    var params = $c.data.getParameter();
    scwin.cvsslMgntNo = params.cvsslMgntNo;

    /////임시/////
    //scwin.cvsslMgntNo = "C1710027";
    //본선 : MJST MAJESTY
    //선사항차 : V1513
    /////임시/////

    const codeOptions = [
        { grpCd: "OP030", compID: "lc_alngpierDrctCd" },   // 접안방향
        { grpCd: "OP193", compID: "lc_stvChrgCls", opt : {"range" : "1"} }   // 하역담당구분
    ]
    $c.data.setCommonCode(codeOptions, scwin.callbackCode);	
    console.log(dlt_commonCodeOP193);
};

scwin.callbackCode = function () {
    $p.setTimeout(function() {
        dlt_commonCodeOP030.insertRow(0);
        //lc_alngpierDrctCd.setSelectedIndex(-1);
    }, {"delay":200});

}

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        udc_comCode.hide();
        //f_dsOrderSearchHeader();
        $c.gus.cfDisableObjects(tb_master);
	    $c.gus.cfDisableObjects(tb_detail);
        scwin.retrieveCombo();

        rd_inQryCond.setValue(0);
        $c.gus.cfEnableObjects([btn_Init]);
	    $c.gus.cfDisableObjects([ed_conVsslCd,ed_conVsslNm,btn_conVsslCd,ed_conShpCoPortCnt,btn_Update,btn_Save,btn_Del]);
        ed_conCvsslMgntNo.focus();

        if(scwin.cvsslMgntNo != null && scwin.cvsslMgntNo != "") {
            ed_conCvsslMgntNo.setValue(scwin.cvsslMgntNo);
            scwin.f_Retrieve();
        }        
    }, {"delay":50});
};




//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {    
    if (ed_conCvsslMgntNo.getValue() == "" && (ed_conVsslCd.getValue() == "" || ed_conShpCoPortCnt.getValue() == "")) {
        alert("조회방법 : 1.본선관리번호 또는 2.본선+선사항차 를 조회조건으로 필수 입력하세요.");
        return;
    } else {
        //ds_Retrieve.UseChangeInfo = "false";
        $c.sbm.execute(sbm_retrieve);
    }

    $c.gus.cfEnableObjects([btn_Init,btn_Update]);
    $c.gus.cfDisableObjects([btn_Save,btn_Del]);
}


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function () {
    //신규버튼을 누르면 저장,업데이트 구분자를 저장으로 셋팅
    scwin.validSaveOrUpdate = 0;

    //ds_op101Master.ClearData();
    dma_op101Master.setEmptyValue();
    ds_op101Master.removeAll();

    //ds_op122detail_import.ClearData();
    dma_op122detail_import.setEmptyValue();
    //ds_op122detail_export.ClearData();
    dma_op122detail_export.setEmptyValue();
    ds_op122detail.removeAll();

    // ljw remove를 왜 하는지..아 첫번째 row 공백이여서
    // dlt_commonCodeOP030.removeRow(0);
    if (dlt_commonCodeOP030.getCellData(0,"grpCd") === ""){
        dlt_commonCodeOP030.removeRow(0);
    }

    //ds_op101Master.AddRow();
    //ds_op122detail_import.AddRow();
    //ds_op122detail_import.NameValue(1,"impExpClsCd") = "I";
    dma_op122detail_import.set("impExpClsCd", "I");
    //ds_op122detail_export.AddRow();
    //ds_op122detail_export.NameValue(1,"impExpClsCd") = "O";
    dma_op122detail_export.set("impExpClsCd", "O");

    $c.gus.cfEnableObjects(tb_master);
    $c.gus.cfEnableObjects(tb_detail);

    $c.gus.cfInitObjects(tb_master  , []);
    $c.gus.cfInitObjects(tb_detail  , []);
    $c.gus.cfInitObjects(tb_retrieve, []);

    //ds_berthPerPier.ClearData();

    ed_lobranCd.setValue("4AA");
    ed_lobranNm.setValue("인천지사");
    ed_portCd.setValue("KRICH");
    ed_portNm.setValue("INCHEON");
    ed_pierCd.setValue("4P13");
    ed_pierNm.setValue("인천북항부두");
    scwin.retrieveCombo();
    //lux_stvChrgCls.Index = "3";
    //console.log(dlt_commonCodeOP193.getAllJSON());
    //console.log(dlt_commonCodeOP193.getCellData(3, "cd"));
    // lc_alngpierDrctCd.setValue("P");
    dma_op101Master.set("alngpierDrctCd", "P");
    lc_stvChrgCls.setValue(dlt_commonCodeOP193.getCellData(3, "cd"));

    ed_lobranCd.focus();
    ed_portCd.focus();
    ed_pierCd.focus();
    ed_shpCoClntNm.focus();

    $c.gus.cfEnableObjects([btn_Init,btn_Save]);
    $c.gus.cfDisableObjects([ed_shpCoClntNo,ed_shpCoClntNm,btn_Update,btn_Del]);

    $c.gus.cfEnableObj(ed_portCd  , false);
    $c.gus.cfEnableObj(ed_portNm , false);
    $c.gus.cfEnableObj(ed_pierCd  , false);
    $c.gus.cfEnableObj(ed_pierNm , false);
    $c.gus.cfEnableObj(ed_lobranCd  , false);
    $c.gus.cfEnableObj(ed_lobranNm , false);
    $c.gus.cfEnableObj(ed_alngpierBittNo , false);
    $c.gus.cfEnableObj(lc_stvChrgCls     , false);
    $c.gus.cfEnableObj(ed_impOdrNo     , false);
    $c.gus.cfEnableObj(ed_expOdrNo     , false);
    $c.gus.cfEnableObj(ed_stvImpOdrNo     , false);
    $c.gus.cfEnableObj(ed_stvExpOdrNo     , false);

    //ed_impShpCoPortCnt.UpperFlag = 1;
    // ed_impShpCoPortCnt event로 대체

    //조회구분 셋팅
    rd_inQryCond.setValue(0);          
}


//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    //수정버튼을 누르면 update 구분자를 1로 셋팅
    // dlt_commonCodeOP030.removeRow(0); //ljw remove 왜 하는지..?
    scwin.validSaveOrUpdate = 1;
    /*
    if ( ds_op122detail_import.CountRow == 0 ) {
        ds_op122detail_import.addrow();
    }
    if ( ds_op122detail_export.CountRow == 0 ) {
        ds_op122detail_export.addrow();
    }
    ds_op101Master.UseChangeInfo        = "false";
    ds_op122detail_import.UseChangeInfo = "false";
    ds_op122detail_export.UseChangeInfo = "false";
    */
    $c.gus.cfEnableObjects(tb_master);
    $c.gus.cfEnableObjects(tb_detail);

    if ( ed_impQty.getValue() == 0 ) {
        ed_impQty.setValue("");
    }
    if ( ed_impWt.getValue()  == 0 ) {
        ed_impWt.setValue("");
    }
    if ( ed_expQty.getValue() == 0 ) { 
        ed_expQty.setValue("");
    }
    if ( ed_expWt.getValue()  == 0 ) {
        ed_expWt.setValue("");
    }

    $c.gus.cfEnableObjects([btn_Init,btn_Save,btn_Del]);
//    $c.gus.cfDisableObjects([btn_Update]);
    $c.gus.cfDisableObjects([ed_shpCoClntNo,ed_shpCoClntNm,btn_Update]);

    $c.gus.cfEnableObj(ed_vsslCd  , false);
    $c.gus.cfEnableObj(ed_vsslNm , false);
    $c.gus.cfEnableObj(btn_vsslCd , false);
    $c.gus.cfEnableObj(ed_portCd  , false);
    $c.gus.cfEnableObj(ed_portNm , false);
    $c.gus.cfEnableObj(ed_pierCd  , false);
    $c.gus.cfEnableObj(ed_pierNm , false);
    $c.gus.cfEnableObj(ed_lobranCd  , false);
    $c.gus.cfEnableObj(ed_lobranNm , false);
    $c.gus.cfEnableObj(ed_alngpierBittNo , false);
    $c.gus.cfEnableObj(lc_stvChrgCls     , false);
    $c.gus.cfEnableObj(ed_impOdrNo     , false);
    $c.gus.cfEnableObj(ed_expOdrNo     , false);
    $c.gus.cfEnableObj(ed_stvImpOdrNo     , false);
    $c.gus.cfEnableObj(ed_stvExpOdrNo     , false);
    //ed_portCd.focus();
}



//-------------------------------------------------------------------------
  // 저장
  //-------------------------------------------------------------------------
scwin.f_Save = async function () {

    /*
  	if ( !ds_op101Master.IsUpdated && !ds_op122detail_import.IsUpdated && !ds_op122detail_export.IsUpdated )
  	{
  	 	cfAlertMsg(MSG_CM_ERR_001,["터미널본선스케줄"]); // "@은(는) 변경된 사항이 없습니다."
  	 	return;
	}
    */

    var masterModLength = dma_op101Master.getModifiedIndex().length;
    var importModLength = dma_op122detail_import.getModifiedIndex().length;
    var exportModLength = dma_op122detail_export.getModifiedIndex().length;

    console.log("masterModLength : "+ masterModLength);
    console.log("importModLength : "+ importModLength);
    console.log("exportModLength : "+ exportModLength);

    if(masterModLength == 0 && importModLength == 0 && exportModLength == 0){
        $c.gus.cfAlertMsg(MSG_CM_ERR_001,["터미널본선스케줄"]); // "@은(는) 변경된 사항이 없습니다."
        return;
    }

	//필수입력항목 체크
    var chk = await $c.gus.cfValidate([saveMandantory]);
    if(!chk) {
        ///임시
        return;
    }

   	//시간체크
   	if ( (ed_arvDt.getValue() + ed_arvHh.getValue()) != "" )
   	{
		if ( (ed_arvHh.getValue().substr(0,2) > "23") || (ed_arvHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("입항일자의 시간 설정이 올바르지 않습니다.");
			  ed_arvHh.focus();
			  return;
	    }
	}

	if ( (ed_alngPierDt.getValue()+ed_alngPierHh.getValue()) != "" )
	{
		if ( (ed_alngPierHh.getValue().substr(0,2) > "23")|| (ed_alngPierHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("접안일시의  시간 설정이 올바르지 않습니다.");
			  ed_alngPierHh.focus();
			  return;
	    }
	}

	if ( (ed_stvStDt.getValue()+ed_stvStHh.getValue()) != "" )
	{
		if ( (ed_stvStHh.getValue().substr(0,2) > "23") || (ed_stvStHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("하역시작일시의 시간 설정이 올바르지 않습니다.");
			  ed_stvStHh.focus();
			  return;
	    }
	}

	if ( (ed_closingTimeDt.getValue()+ed_closingTimeHh.getValue()) != "" )
	{
		if ( (ed_closingTimeHh.getValue().substr(0,2) > "23") || (ed_closingTimeHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("Closing일시의 시간 설정이 올바르지 않습니다.");
			  ed_closingTimeHh.focus();
			  return;
	    }
	    if ( ed_arvIntendDt.getValue().trim()+ed_arvIntendHh.getValue().trim() < ed_closingTimeDt.getValue().trim()+ed_closingTimeHh.getValue().trim() )
	    {
	    	$c.win.alert("입항예정일시는  Closing일시보다 이후여야 합니다.");
	    	ed_arvIntendDt.focus();
    		return;
   		}
	}

	if ( (ed_stvEndDt.getValue()+ed_stvEndHh.getValue()) != "" )
	{
		if ( (ed_stvEndHh.getValue().substr(0,2) > "23") || (ed_stvEndHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("하역종료일시의 시간 설정이 올바르지 않습니다.");
			  ed_stvEndHh.focus();
			  return;
	    }
	}

	if ( (ed_offPierDt.getValue()+ed_offPierHh.getValue()) != "" )
	{
		if ( (ed_offPierHh.getValue().substr(0,2) > "23") || (ed_offPierHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("이안일시의  시간 설정이 올바르지 않습니다.");
			  ed_offPierHh.focus();
			  return;
	    }
	}

	if ( (ed_dptDt.getValue()+ed_dptHh.getValue()) != "" )
	{
		if ( (ed_dptHh.getValue().substr(0,2) > "23") || (ed_dptHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("출항일시의  시간 설정이 올바르지 않습니다.");
			  ed_dptHh.focus();
			  return;
	    }
	}

	if ( (ed_dptIntendDt.getValue() + ed_dptIntendHh.getValue()) != "" )
	{
		if ( (ed_dptIntendHh.getValue().substr(0,2) > "23") || (ed_dptIntendHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("출항일시의  시간 설정이 올바르지 않습니다.");
			  ed_dptIntendHh.focus();
			  return;
	    }
	}

	if ( (ed_arvIntendDt.getValue()+ed_arvIntendHh.getValue()) != "" )
	{
		if ( (ed_arvIntendHh.getValue().substr(0,2) > "23") || (ed_arvIntendHh.getValue().substr(2,2) > "59") )
		{
			  $c.win.alert("출항일시의  시간 설정이 올바르지 않습니다.");
			  ed_arvIntendHh.focus();
			  return;
	    }
	}

   	//일시 validation 체크
   	if ( (ed_dptIntendDt.getValue()+ed_dptIntendHh.getValue()) < (ed_arvIntendDt.getValue()+ed_arvIntendHh.getValue()) )
   	{
   		$c.win.alert("출항예정일시는 입항예정일시보다 이후여야 합니다.");
   		ed_dptIntendDt.focus();
   		return;
   	}

   	//일시 validation 체크
   	var v_arvDtm1         = ed_arvDt.getValue().trim()         + ed_arvHh.getValue().trim();
   	var v_alngPierDtm1    = ed_alngPierDt.getValue().trim()    + ed_alngPierHh.getValue().trim();
   	var v_alngPierDtm2    = ed_alngPierDt.getValue().trim()    + ed_alngPierHh.getValue().trim();
   	var v_stvStDtm1       = ed_stvStDt.getValue().trim()       + ed_stvStHh.getValue().trim();
   	var v_stvStDtm2       = ed_stvStDt.getValue().trim()       + ed_stvStHh.getValue().trim();
   	var v_closingTimeDtm1 = ed_closingTimeDt.getValue().trim() + ed_closingTimeHh.getValue().trim();
   	var v_closingTimeDtm2 = ed_closingTimeDt.getValue().trim() + ed_closingTimeHh.getValue().trim();
   	var v_stvEndDtm1      = ed_stvEndDt.getValue().trim()      + ed_stvEndHh.getValue().trim();
   	var v_stvEndDtm2      = ed_stvEndDt.getValue().trim()      + ed_stvEndHh.getValue().trim();
   	var v_offPierDtm1     = ed_offPierDt.getValue().trim()     + ed_offPierHh.getValue().trim();
   	var v_offPierDtm2     = ed_offPierDt.getValue().trim()     + ed_offPierHh.getValue().trim();
   	var v_dptDtm1         = ed_dptDt.getValue().trim()         + ed_dptHh.getValue().trim();

   	if ( $c.gus.cfIsNull(v_arvDtm1) ) {
        v_arvDtm1 = '000000000000';
    }

   	//접안일시 체크
   	if ( !$c.gus.cfIsNull(v_alngPierDtm1) )
   	{
		if ( v_arvDtm1 > v_alngPierDtm1 )
		{
			$c.win.alert("접안일시는 입항일시보다 이후여야 합니다.");
			ed_alngPierDt.focus();
    		return;
		}
	}
	//하역시작일시 체크
	if ( !$c.gus.cfIsNull(v_stvStDtm1) )
	{
    	if ( $c.gus.cfIsNull(v_alngPierDtm1) )
    	{
			if ( v_arvDtm1 > v_stvStDtm1 )
			{
				$c.win.alert("하역시작일시는 입항일시보다 이후여야 합니다.");
				ed_stvStDt.focus();
	    		return;
			}
    	} else {
			if (v_alngPierDtm1 > v_stvStDtm1)
			{
				$c.win.alert("하역시작일시는 접안일시보다 이후여야 합니다.");
				ed_stvStDt.focus();
	    		return;
			}
    	}
    }
   	//하역종료일시 체크
   	if ( !$c.gus.cfIsNull(v_stvEndDtm1) )
   	{
    	if ( $c.gus.cfIsNull(v_stvStDtm1) )
    	{
	    	if ( $c.gus.cfIsNull(v_alngPierDtm1) )
	    	{
				if ( v_arvDtm1 > v_stvEndDtm1 )
				{
					$c.win.alert("하역종료일시는 입항일시보다 이후여야 합니다.");
					ed_stvEndDt.focus();
		    		return;
				}
	    	} else {
				if ( v_alngPierDtm1 > v_stvEndDtm1 )
				{
					$c.win.alert("하역종료일시는 접안일시보다 이후여야 합니다.");
					ed_stvEndDt.focus();
		    		return;
				}
	    	}
    	} else {
			if ( v_stvStDtm1 > v_stvEndDtm1 )
			{
				$c.win.alert("하역종료일시는 하역시작일시보다 이후여야 합니다.");
				ed_stvEndDt.focus();
	    		return;
			}
    	}
    }

	//이안일시 체크
	if ( !$c.gus.cfIsNull(v_offPierDtm1) )
	{
		if ( $c.gus.cfIsNull(v_stvEndDtm1) )
		{
	    	if ( $c.gus.cfIsNull(v_stvStDtm1) )
	    	{
		    	if ( $c.gus.cfIsNull(v_alngPierDtm1) )
		    	{
					if ( v_arvDtm1 > v_offPierDtm1 )
					{
						$c.win.alert("이안일시는 입항일시보다 이후여야 합니다.");
						ed_offPierDt.focus();
			    		return;
					}
		    	} else {
					if ( v_alngPierDtm1 > v_offPierDtm1 )
					{
						$c.win.alert("이안일시는 접안일시보다 이후여야 합니다.");
						ed_offPierDt.focus();
			    		return;
					}
		    	}
	    	} else {
				if ( v_stvStDtm1 > v_offPierDtm1 )
				{
					$c.win.alert("이안일시는 하역시작일시보다 이후여야 합니다.");
					ed_offPierDt.focus();
		    		return;
				}
	    	}
	    } else {
			if ( v_stvEndDtm1 > v_offPierDtm1 )
			{
				$c.win.alert("이안일시는 하역종료일시보다 이후여야 합니다.");
				ed_offPierDt.focus();
	    		return;
			}
	    }
	}
	//출항일시 체크
	if ( !$c.gus.cfIsNull(v_dptDtm1) )
	{
		if ( $c.gus.cfIsNull(v_offPierDtm1) )
		{
			if ( $c.gus.cfIsNull(v_stvEndDtm1) )
			{
		    	if ( $c.gus.cfIsNull(v_stvStDtm1) )
		    	{
			    	if ( $c.gus.cfIsNull(v_alngPierDtm1) )
			    	{
						if ( v_arvDtm1 > v_dptDtm1 )
						{
							$c.win.alert("출항일시는 입항일시보다 이후여야 합니다.");
							ed_dptDt.focus();
				    		return;
						}
			    	} else {
						if ( v_alngPierDtm1 > v_dptDtm1 )
						{
							$c.win.alert("출항일시는 접안일시보다 이후여야 합니다.");
							ed_dptDt.focus();
				    		return;
						}
			    	}
		    	} else {
					if ( v_stvStDtm1 > v_dptDtm1 )
					{
						$c.win.alert("출항일시는 하역시작일시보다 이후여야 합니다.");
						ed_dptDt.focus();
			    		return;
					}
		    	}
		    } else {
				if ( v_stvEndDtm1 > v_dptDtm1 )
				{
					$c.win.alert("출항일시는 하역종료일시보다 이후여야 합니다.");
					ed_dptDt.focus();
		    		return;
				}
		    }
		} else {
			if ( v_offPierDtm1 > v_dptDtm1 )
			{
				$c.win.alert("출항일시는 이안일시보다 이후여야 합니다.");
				ed_dptDt.focus();
	    		return;
			}
		}
	}
    //alert(ds_op122detail_import.text);
    var chkAlert = await $c.win.confirm(MSG_CM_CRM_001);
    if ( !chkAlert ) {
        return;
    }

	//validSaveOrUpdate 값에 따라서 저장/수정 선택처리
	var importCheckFlag = 0;
    var exportCheckFlag = 0;

    if ( scwin.validSaveOrUpdate == 0 ){
        if (   ed_impShpCoPortCnt.getValue() == ""
            && ed_impRepClntNo.getValue()    == ""
            && ed_impRepKcgCd.getValue()     == ""
            && ["","0"].includes(ed_impQty.getValue())
            && ["","0"].includes(ed_impWt.getValue()) ){
    		importCheckFlag = 1;
    	}

    	if (   ed_expShpCoPortCnt.getValue() == ""
    	    && ed_expRepClntNo.getValue()    == ""
    	    && ed_expRepKcgCd.getValue()     == ""
            && ["","0"].includes(ed_expQty.getValue())
            && ["","0"].includes(ed_expWt.getValue()) ){                
    		exportCheckFlag = 1;
    	}

    	if ( importCheckFlag == 1 && exportCheckFlag == 1 ){
    		$c.win.alert("수,출입 상세정보를 입력하셔야 합니다.");
    		return;
    	} else if ( importCheckFlag == 0 && ed_impShpCoPortCnt.getValue() == "" ) {// 수입의 다른 항목값이 입력된  경우.    	
            $c.gus.cfAlertMsg(MSG_CM_ERR_002,["수입의 선사항차"]); //"@은(는) 필수 입력 항목입니다.";
    		return;
    	}

    	if ( importCheckFlag == 1 ) {            
            dma_op122detail_import.setEmptyValue(); 
            ds_op122detail_import.removeAll();
            dma_op122detail.setJSON(dma_op122detail_export.getJSON());
            ds_op122detail_export.setRowJSON(0, dma_op122detail_export.getJSON());                
        }
    	if ( exportCheckFlag == 1 ) {
            dma_op122detail_export.setEmptyValue();    
            ds_op122detail_export.removeAll();
            dma_op122detail.setJSON(dma_op122detail_import.getJSON());    
            ds_op122detail_import.setRowJSON(0, dma_op122detail_import.getJSON());
        }

        console.log("dma_op101Master : ");
        console.log(dma_op101Master);
        console.log("dma_op122detail_import : ");
        console.log(dma_op122detail_import);
        console.log("dma_op122detail_export : ");
        console.log(dma_op122detail_export);

        ds_op101Master.setRowJSON(0, dma_op101Master.getJSON());
        //ds_op122detail_import.setRowJSON(0, dma_op122detail_import.getJSON(),true);
        //ds_op122detail_import.setRowJSON(0, dma_op122detail_import.getJSON());
        //ds_op122detail_export.setRowJSON(0, dma_op122detail_export.getJSON());                

    	await $c.sbm.execute(sbm_save);

    } else if ( scwin.validSaveOrUpdate == 1 ) {

		if (   ed_impShpCoPortCnt.getValue() == ""
		    && ed_impRepClntNo.getValue()    == ""
		    && ed_impRepKcgCd.getValue()     == ""
		    && ed_impQty.getValue()         == ""
		    && ed_impWt.getValue()          == "" )
		{
    		importCheckFlag = 1;
    	}

    	if (   ed_expShpCoPortCnt.getValue() == ""
    	    && ed_expRepClntNo.getValue()    == ""
    	    && ed_expRepKcgCd.getValue()     == ""
    	    && ed_expQty.getValue()         == ""
    	    && ed_expWt.getValue()          == "" )
    	{
    		exportCheckFlag = 1;
    	}

    	if ( importCheckFlag == 1 && exportCheckFlag == 1 )
    	{
    		$c.win.alert("수,출입 상세정보를 입력하셔야 합니다.");
    		return;
    	}

    	//ClearData로 없어진 impExpClsCd를 셋팅해준다.
    	if ( importCheckFlag == 0 ) {
            dma_op122detail_import.set("impExpClsCd" , "I");
        }
    	if ( exportCheckFlag == 0 ) {
            dma_op122detail_export.set("impExpClsCd" , "O");
        }

        ds_op101Master.setRowJSON(0, dma_op101Master.getJSON());
        //ds_op122detail_import.setRowJSON(0, dma_op122detail_import.getJSON(),true);
        ds_op122detail_import.setRowJSON(0, dma_op122detail_import.getJSON());
        ds_op122detail_export.setRowJSON(0, dma_op122detail_export.getJSON());

    	$c.sbm.execute(sbm_update);
    }

    //cfDisableObjects([btn_Save]);
}

