// 조회,저장시 OUT
scwin.op101Master_load = function () {
    var rowCnt = ds_op101Master.getRowCount();

    if ( rowCnt == 0 ) {
		$c.win.alert("조회된 Data가 없습니다.");
		dma_op122detail_import.setEmptyValue();
		dma_op122detail_export.setEmptyValue();
    }

    ed_conCvsslMgntNo.setValue(ds_op101Master.getCellData(0 ,"cvsslMgntNo"));

    $c.gus.cfSetHiddenValue(ed_vsslCd, ed_vsslCd.getValue());
	$c.gus.cfSetHiddenValue(ed_vsslNm, ed_vsslNm.getValue());
	$c.gus.cfDisableObjects(tb_master);
	$c.gus.cfDisableObjects(tb_detail);

	var berthNo = ds_op101Master.getCellData(0,"berthNo");

	//부두별 선석 조회위한 Reset
    /*
	ds_berthPerPier.DataId = "/cm.zz.RetrieveComboCMD.do"
	                       + "?sysCd=TerminalCarryingVesselScheduleEBC"
	                       + "&queryId=retrieveBerthCd"
	                       + "&param1=" + ds_op101Master.Namevalue(1,"pierCd");

	ds_berthPerPier.Reset();
    */
    scwin.retrieveCombo();

	//lc_berthPerPier.setValue(berthNo);
}

// 조회,저장시 OUT
scwin.op122detail_load = function () {    
    var rowCnt = ds_op122detail.getRowCount();
    var gubun = "";

	if( rowCnt == 0 ){		
		ds_op122detail.removeAll();
		dma_op122detail_import.setEmptyValue();
		dma_op122detail_export.setEmptyValue();
	}else {
		for(var i=0; i < ds_op122detail.getRowCount() ; i++) {
			if(ds_op122detail.getCellData(i,"impExpClsCd")=="I") {                
				//$c.gus.cfCopyDataSet(ds_op122detail, ds_op122detail_import, "copyHeader=yes,rowFrom="+i+",rowCnt=1");		
                dma_op122detail_import.setJSON(ds_op122detail.getRowJSON(i));
			}else if(ds_op122detail.getCellData(i,"impExpClsCd")=="O") {
				//$c.gus.cfCopyDataSet(ds_op122detail, ds_op122detail_export, "copyHeader=yes,rowFrom="+i+",rowCnt=1");		
                dma_op122detail_export.setJSON(ds_op122detail.getRowJSON(i));
			}
			gubun = ds_op122detail.getCellData(i,"impExpClsCd");
		}//for

		if(ds_op122detail.getRowCount() == 1 && gubun == "I"){
			dma_op122detail_export.setEmptyValue();
		}else if (ds_op122detail.getRowCount() == 1 && gubun == "O"){
			dma_op122detail_import.setEmptyValue();            
		}			
	}
}

