scwin.sbm_berthCd_submitdone = function (e) {    
    console.log("before : ");
    console.log(dma_op101Master.getJSON());
    if(e.responseJSON.GAUCE) {                
        ds_berthPerPier.setJSON(e.responseJSON.GAUCE);

        console.log("after : ");
        console.log(dma_op101Master.getJSON());
        var berthNo = ds_op101Master.getCellData(0,"berthNo");
        $p.setTimeout(function() {            
            console.log("berthNo::",berthNo);

            if(berthNo != "" && berthNo != null){
                lc_berthPerPier.setValue(berthNo);
            } else {
                // alert(ds_berthPerPier.getCellData(0, "code"));
                lc_berthPerPier.setValue(ds_berthPerPier.getCellData(0, "code"));
                //ed_alngpierBittNo.setSelectedIndex(1);
                //alert(lc_berthPerPier.getValue());
                //alert(lc_berthPerPier.getSelectedIndex()+1);
                ed_alngpierBittNo.setValue(ds_berthPerPier.getCellData(lc_berthPerPier.getSelectedIndex(), "basisBitt"));    
            }
        }, {"delay":100});
    }
};


scwin.ed_alngpierBittNo_onchange = function (info) {    
    let arrMatched = ds_berthPerPier.getMatchedJSON("basisBitt", "07");
    if (arrMatched.length> 0) {
        ed_berthCd.setValue(arrMatched[0].berthCd);
    }
};
